import os
from cryptography.fernet import Fernet

# Generate and load encryption key
def load_or_generate_key(key_path='encryption.key'):
    if not os.path.exists(key_path):
        key = Fernet.generate_key()
        with open(key_path, 'wb') as key_file:
            key_file.write(key)
    else:
        with open(key_path, 'rb') as key_file:
            key = key_file.read()
    return key

# Initialize the Fernet cipher suite
encryption_key = load_or_generate_key()
cipher_suite = Fernet(encryption_key)

def encrypt_credit_card(card_number):
    """
    Encrypts a credit card number using AES encryption.
    
    Args:
    card_number (str): The credit card number to be encrypted.
    
    Returns:
    str: The encrypted credit card number.
    """
    return cipher_suite.encrypt(card_number.encode()).decode()

def decrypt_credit_card(encrypted_card_number):
    """
    Decrypts a previously encrypted credit card number.
    
    Args:
    encrypted_card_number (str): The encrypted credit card number to be decrypted.
    
    Returns:
    str: The original credit card number.
    """
    return cipher_suite.decrypt(encrypted_card_number.encode()).decode()

# Example usage
if __name__ == "__main__":
    card_number = "1234-5678-9012-3456"
    encrypted = encrypt_credit_card(card_number)
    print(f"Encrypted: {encrypted}")
    
    decrypted = decrypt_credit_card(encrypted)
